#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=5005;
int n,u[N],v[N],w[N],dis[N],uu,vv,vis[N],ans=0x3f3f3f3f;
struct node
{
	int v,w;
};
vector<node> g[N];
void dfs(int u1,int f)
{
	for(int i=0;i<g[u1].size();i++)
	{
		int v1=g[u1][i].v;
		if((v1==f)||(u1==uu&&v1==vv)||(u1==vv&&v1==uu)) continue;
		dis[v1]=dis[u1]+g[u1][i].w;
		dfs(v1,u1);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<n;i++)
	{
		cin>>u[i]>>v[i]>>w[i];
		g[u[i]].push_back(node{v[i],w[i]});
		g[v[i]].push_back(node{u[i],w[i]});
	}
	for(int i=1;i<n;i++)
	{
		memset(dis,0,sizeof(dis));
		memset(vis,0,sizeof(vis));
		dis[0]=-1;
		uu=u[i],vv=v[i];
		dfs(u[i],0);
		vis[u[i]]=1;
		int s1=0,s2=0,t1=0,t2=0,mid1=0,mid2=0;
		for(int i=1;i<=n;i++)
		{
			if(dis[i]>0) vis[i]=1;
			if(dis[i]>dis[s1]) s1=i;
		}
		dis[s1]=0;
		dfs(s1,0);
		for(int i=1;i<=n;i++)
		{
			if(dis[i]>dis[t1]) t1=i;
		}
		for(int i=1;i<=n;i++)
		{
			if(max(dis[t2]-dis[i],dis[i])<max(dis[t2]-dis[mid1],dis[mid1])&&dis[i]>dis[mid1]) mid1=i;
		}
		dfs(v[i],0);
		for(int i=1;i<=n;i++)
		{
			if(vis[i]==0&&dis[i]>dis[s2]) s2=i;
		}
		dis[s2]=0;
		dfs(s2,0);
		for(int i=1;i<=n;i++)
		{
			if(vis[i]==0&&dis[i]>dis[t2]) t2=i;
		}
		for(int i=1;i<=n;i++)
		{
			if(vis[i]==0&&max(dis[t2]-dis[i],dis[i])<max(dis[t2]-dis[mid2],dis[mid2])&&dis[i]>dis[mid2]) mid2=i;// max(dis[t2]-dis[i],dis[i])
		}
//		cout<<i<<"  ( s1:"<<s1<<" t1:"<<t1<<" mid1:"<<mid1<<" , s2:"<<s2<<" t2:"<<t2<<" mid2:"<<mid2<<")\n";
		ans=min(ans,max(max(dis[t1],dis[t2]),dis[t1]-dis[mid1]+dis[t2]-dis[mid2]+w[i]));
	}
	cout<<ans;
	return 0;
}
